export function nextGeneration(livingCells: Cell[]): Cell[] {
  const survivors = livingCells.filter((cell) => {
    const neighbors = countLivingNeighbors(cell, livingCells);
    return neighbors === 2 || neighbors === 3;
  });

  const deadCandidates: Cell[] = [];
  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        const isLiving = livingCells.some(([cx, cy]) => cx === candidate[0] && cy === candidate[1]);
        const alreadyAdded = deadCandidates.some(([cx, cy]) => cx === candidate[0] && cy === candidate[1]);
        if (!isLiving && !alreadyAdded) {
          deadCandidates.push(candidate);
        }
      }
    }
  }

  const born = deadCandidates.filter((cell) => countLivingNeighbors(cell, livingCells) === 3);

  return [...survivors, ...born];
}
